local ModName, Sequences = ...
local GSE = rawget(_G, "GSE") or rawget(_G, "GSE3")
if GSE == nil then print("GSE3-Warlock-Midnight requires GSE.") return end

-- Level 84-90 Compatible Warlock Sequences
-- CORRECT GSE3 CBOR FORMAT — spells use [known:] guards

Sequences["WL_AFF_SSH_ST"] = [[!GSE3!]]
Sequences["WL_AFF_SSH_AOE"] = [[!GSE3!]]
Sequences["WL_AFF_HCL_ST"] = [[!GSE3!]]
Sequences["WL_DEMO_SSH_ST"] = [[!GSE3!]]
Sequences["WL_DEMO_DIA_AOE"] = [[!GSE3!]]
Sequences["WL_DST_HCL_ST"] = [[!GSE3!]]
Sequences["WL_DST_DIA_CLV"] = [[!GSE3!]]

GSE.RegisterAddon(
  ModName,
  C_AddOns.GetAddOnMetadata(ModName, "Version"),
  GSE.GetSequenceNamesFromLibrary(Sequences),
  Sequences
)
